export interface Memory {
  id: string;
  content: string;
  category: 'FACT' | 'EMOTION' | 'EVENT' | 'PREDICTION';
  timestamp: number;
  confidence: number; // 0-1
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
  relatedMemories?: string[]; // IDs of memories used for this answer
}

export interface FiveElementsData {
  subject: string;
  A: number; // User Value
  fullMark: number;
}

export interface EnergyPoint {
  time: string;
  energy: number;
}

export enum AppRoute {
  DASHBOARD = 'dashboard',
  ORACLE = 'oracle',
  DATABASE = 'database',
  WELLNESS = 'wellness'
}

import { Memory } from '../types';
import { v4 as uuidv4 } from 'uuid';

const STORAGE_KEY = 'destiny_os_memories';

// Mock initial memories for the "Cold Start" experience
const INITIAL_MEMORIES: Memory[] = [
  {
    id: '1',
    content: 'User was born in 1995, Year of the Wood Pig.',
    category: 'FACT',
    timestamp: Date.now() - 10000000,
    confidence: 1.0,
  },
  {
    id: '2',
    content: 'Expresses anxiety regarding career stagnation.',
    category: 'EMOTION',
    timestamp: Date.now() - 5000000,
    confidence: 0.8,
  },
  {
    id: '3',
    content: 'Prefers meditation over physical exercise.',
    category: 'FACT',
    timestamp: Date.now() - 200000,
    confidence: 0.9,
  }
];

export const getMemories = (): Memory[] => {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (!stored) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_MEMORIES));
    return INITIAL_MEMORIES;
  }
  return JSON.parse(stored);
};

export const addMemory = (content: string, category: Memory['category']): Memory => {
  const memories = getMemories();
  const newMemory: Memory = {
    id: uuidv4(),
    content,
    category,
    timestamp: Date.now(),
    confidence: 0.9, // In a real app, AI would score this
  };
  const updated = [newMemory, ...memories];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  return newMemory;
};

export const deleteMemory = (id: string): void => {
  const memories = getMemories();
  const updated = memories.filter(m => m.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
};

export const getContextString = (): string => {
  const memories = getMemories();
  if (memories.length === 0) return "No prior context available.";

  return memories.map(m => `[${m.category}] ${m.content}`).join('\n');
};

import { GoogleGenAI, ChatSession } from "@google/genai";
import { SYSTEM_INSTRUCTION } from '../constants';
import { getContextString, addMemory } from './memoryService';

// Initialize Gemini Client
// In a real app, we would manage the instance lifecycle better, but this is fine for the demo.
let chatSession: ChatSession | null = null;
let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    if (!process.env.API_KEY) {
      console.error("API_KEY is missing from environment variables.");
      throw new Error("API Key missing");
    }
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

export const initializeChat = async () => {
  const client = getClient();
  const context = getContextString();

  const fullSystemInstruction = `${SYSTEM_INSTRUCTION}\n\nCURRENT USER CONTEXT (LIFE DATABASE):\n${context}`;

  chatSession = client.chats.create({
    model: 'gemini-2.5-flash-latest', // Fast model for chat
    config: {
      systemInstruction: fullSystemInstruction,
      temperature: 0.7,
    },
  });
};

export const sendMessageToOracle = async (message: string): Promise<string> => {
  if (!chatSession) {
    await initializeChat();
  }

  if (!chatSession) {
    throw new Error("Failed to initialize chat session");
  }

  try {
    const response = await chatSession.sendMessage({ message });

    // Simulate "Memory Extraction" (Post-processing)
    // In a real app, we might run a second lightweight LLM call to extract facts.
    // Here, we'll just heuristically save the interaction if it's long enough as an "event".
    if (message.length > 20 && Math.random() > 0.7) {
        addMemory(`User asked about: "${message.substring(0, 50)}..."`, 'EVENT');
    }

    return response.text || "The Oracle is silent (No response text).";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "The cosmic connection is disrupted. Please check your API key or network.";
  }
};

