import React, { useState, useEffect, useRef } from 'react';
import { sendMessageToOracle } from '../services/geminiService';
import { ChatMessage } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { PaperAirplaneIcon, SparklesIcon } from '@heroicons/react/24/solid';

const OracleChat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
        role: 'model',
        text: 'Greetings, seeker. The database of your destiny lies open before me. What guidance do you seek today?',
        timestamp: Date.now()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendMessageToOracle(userMsg.text);
      const aiMsg: ChatMessage = {
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, {
          role: 'model',
          text: "The void is silent. (Connection Error)",
          timestamp: Date.now()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-120px)] glass-panel rounded-2xl overflow-hidden border border-white/10">
      {/* Chat Header */}
      <div className="p-4 border-b border-white/10 bg-black/40 flex items-center justify-between">
         <div className="flex items-center gap-3">
            <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
            <h3 className="font-serif text-[#D4AF37]">The Oracle</h3>
         </div>
         <span className="text-xs text-gray-500 font-mono">GEMINI-2.5-FLASH // RAG-ACTIVE</span>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        <AnimatePresence initial={false}>
            {messages.map((msg, idx) => (
            <motion.div 
                key={idx} 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
                <div 
                    className={`max-w-[85%] lg:max-w-[70%] p-4 rounded-2xl ${
                        msg.role === 'user' 
                        ? 'bg-[#8B0000]/20 border border-[#8B0000]/50 text-gray-100 rounded-br-none' 
                        : 'bg-white/5 border border-white/10 text-gray-300 rounded-bl-none'
                    }`}
                >
                    <div className="prose prose-invert prose-sm max-w-none leading-relaxed whitespace-pre-wrap font-light">
                        {msg.text.split('\n').map((line, i) => (
                            <p key={i} className="mb-2 last:mb-0">{line}</p>
                        ))}
                    </div>
                    <div className="mt-2 text-[10px] text-gray-500 text-right uppercase tracking-widest opacity-50">
                        {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                    </div>
                </div>
            </motion.div>
            ))}
        </AnimatePresence>

        {isLoading && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex justify-start">
                 <div className="bg-white/5 border border-white/10 p-4 rounded-2xl rounded-bl-none flex items-center gap-2">
                    <SparklesIcon className="w-4 h-4 text-[#D4AF37] animate-spin" />
                    <span className="text-xs text-gray-400">Consulting the Life Database...</span>
                 </div>
            </motion.div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-black/40 border-t border-white/10">
        <div className="relative">
            <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                placeholder="Ask about your destiny..."
                className="w-full bg-[#111] text-gray-200 rounded-xl pl-4 pr-12 py-4 border border-white/10 focus:border-[#D4AF37] focus:ring-1 focus:ring-[#D4AF37] outline-none resize-none h-14 min-h-[56px]"
                disabled={isLoading}
            />
            <button 
                onClick={handleSend}
                disabled={isLoading || !input.trim()}
                className="absolute right-2 top-2 bottom-2 aspect-square flex items-center justify-center bg-[#D4AF37] hover:bg-[#b5952f] text-black rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
                <PaperAirplaneIcon className="w-5 h-5 -ml-0.5" />
            </button>
        </div>
        <p className="text-[10px] text-gray-600 text-center mt-2">
            AI can make mistakes. Please verify important life decisions.
        </p>
      </div>
    </div>
  );
};

export default OracleChat;

import React, { useState, useEffect } from 'react';
