  const handleDelete = (id: string) => {
    deleteMemory(id);
    setMemories(getMemories());
  };

  const getCategoryColor = (cat: string) => {
    switch (cat) {
        case 'FACT': return 'text-blue-400 border-blue-400/30 bg-blue-400/10';
        case 'EMOTION': return 'text-purple-400 border-purple-400/30 bg-purple-400/10';
        case 'EVENT': return 'text-green-400 border-green-400/30 bg-green-400/10';
        default: return 'text-gray-400 border-gray-400/30 bg-gray-400/10';
