                    </div>
                </motion.div>
            ))}
        </AnimatePresence>

        {/* Add Memory Placeholder (Visual only for now) */}
        <div className="border border-dashed border-white/10 rounded-xl p-5 flex flex-col items-center justify-center text-gray-600 cursor-not-allowed bg-white/5 hover:bg-white/10 transition-colors min-h-[150px]">
            <span className="text-2xl mb-2">+</span>
            <span className="text-sm">Add Manual Entry</span>
            <span className="text-[10px] mt-1">(Coming in v2.0)</span>
        </div>
      </div>
    </div>
  );
};

export default LifeDatabase;

import React, { useState } from 'react';
import { motion } from 'framer-motion';

const Wellness: React.FC = () => {
  const [count, setCount] = useState(0);
  const [ripples, setRipples] = useState<{id: number, x: number, y: number}[]>([]);

  const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
    setCount(c => c + 1);

    // Create ripple effect
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const newRipple = { id: Date.now(), x, y };
    setRipples(prev => [...prev, newRipple]);

    // Cleanup ripple
    setTimeout(() => {
        setRipples(prev => prev.filter(r => r.id !== newRipple.id));
    }, 1000);
  };

  return (
    <div className="flex flex-col items-center justify-center h-[calc(100vh-140px)] space-y-12">
      <div className="text-center space-y-2">
         <h2 className="text-4xl font-serif text-[#D4AF37]">Digital Wooden Fish</h2>
         <p className="text-gray-400 font-light">Tap to accumulate merit and calm the mind.</p>
      </div>

      <div className="relative">
          <motion.button
            whileTap={{ scale: 0.95 }}
            onClick={handleClick}
            className="w-64 h-64 rounded-full bg-gradient-to-b from-[#1a1a1a] to-black border-4 border-[#333] shadow-[0_0_50px_rgba(0,0,0,0.8)] relative overflow-hidden group outline-none"
          >
             {/* Center Icon */}
             <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                 <svg viewBox="0 0 24 24" fill="currentColor" className="w-32 h-32 text-[#8B0000] opacity-50 group-hover:opacity-80 transition-opacity">
                    <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 18c-4.41 0-8-3.59-8-8s3.59-8 8-8 8 3.59 8 8-3.59 8-8 8zm-5-9h10v2H7z"/>
                 </svg>
             </div>

             {/* Ripples */}
             {ripples.map(r => (
                 <motion.span
                    key={r.id}
                    initial={{ scale: 0, opacity: 0.5 }}
                    animate={{ scale: 4, opacity: 0 }}
                    transition={{ duration: 0.8 }}
                    style={{ left: r.x, top: r.y }}
                    className="absolute w-10 h-10 bg-[#D4AF37] rounded-full pointer-events-none transform -translate-x-1/2 -translate-y-1/2"
                 />
             ))}
          </motion.button>

          {/* Floating Merits */}
          <div className="absolute -top-10 left-1/2 transform -translate-x-1/2 h-10 w-full flex justify-center pointer-events-none">
             {ripples.map(r => (
                 <motion.div
                    key={'text-' + r.id}
                    initial={{ y: 20, opacity: 1 }}
                    animate={{ y: -50, opacity: 0 }}
                    transition={{ duration: 1 }}
                    className="absolute text-[#D4AF37] font-serif font-bold text-xl"
                 >
                    Merit +1
                 </motion.div>
             ))}
          </div>
      </div>

      <div className="bg-white/5 px-8 py-4 rounded-full border border-white/10">
          <span className="text-gray-400 uppercase tracking-widest text-xs">Total Merit: </span>
          <span className="text-2xl font-serif text-[#D4AF37] ml-2">{count}</span>
      </div>
    </div>
  );
};

export default Wellness;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import OracleChat from './components/OracleChat';
import LifeDatabase from './components/LifeDatabase';
import Wellness from './components/Wellness';
import { AppRoute } from './types';

function App() {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);

  const renderContent = () => {
    switch (route) {
      case AppRoute.DASHBOARD:
        return <Dashboard />;
      case AppRoute.ORACLE:
        return <OracleChat />;
      case AppRoute.DATABASE:
        return <LifeDatabase />;
      case AppRoute.WELLNESS:
        return <Wellness />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <Layout currentRoute={route} setRoute={setRoute}>
      {renderContent()}
    </Layout>
  );
}

export default App;

import { Memory } from '../types';
import { v4 as uuidv4 } from 'uuid';

const STORAGE_KEY = 'destiny_os_memories';

// Mock initial memories for the "Cold Start" experience
const INITIAL_MEMORIES: Memory[] = [
  {
    id: '1',
    content: '用户生于1995年，乙亥猪年（木猪）。',
    category: 'FACT',
    timestamp: Date.now() - 10000000,
    confidence: 1.0,
  },
  {
    id: '2',
    content: '最近表达了对职业发展停滞的焦虑感。',
    category: 'EMOTION',
    timestamp: Date.now() - 5000000,
    confidence: 0.8,
  },
  {
    id: '3',
    content: '比起剧烈运动，更倾向于冥想和静态活动。',
    category: 'FACT',
    timestamp: Date.now() - 200000,
    confidence: 0.9,
  }
];

export const getMemories = (): Memory[] => {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (!stored) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_MEMORIES));
    return INITIAL_MEMORIES;
  }
  return JSON.parse(stored);
};

export const addMemory = (content: string, category: Memory['category']): Memory => {
  const memories = getMemories();
  const newMemory: Memory = {
    id: uuidv4(),
    content,
    category,
    timestamp: Date.now(),
    confidence: 0.9, // In a real app, AI would score this
  };
  const updated = [newMemory, ...memories];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  return newMemory;
};

export const deleteMemory = (id: string): void => {
  const memories = getMemories();
  const updated = memories.filter(m => m.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
};

export const getContextString = (): string => {
  const memories = getMemories();
  if (memories.length === 0) return "暂无历史档案。";

  return memories.map(m => `[${m.category}] ${m.content}`).join('\n');
};

import React from 'react';
import { AppRoute } from '../types';
import { 
  ChartPieIcon, 
  ChatBubbleLeftRightIcon, 
  ArchiveBoxIcon, 
  HeartIcon, 
} from '@heroicons/react/24/outline';

