import React, { useState } from 'react';
import { motion } from 'framer-motion';

const Wellness: React.FC = () => {
  const [count, setCount] = useState(0);
  const [ripples, setRipples] = useState<{id: number, x: number, y: number}[]>([]);

  const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
    setCount(c => c + 1);

    // Create ripple effect
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const newRipple = { id: Date.now(), x, y };
    setRipples(prev => [...prev, newRipple]);

    // Cleanup ripple
    setTimeout(() => {
        setRipples(prev => prev.filter(r => r.id !== newRipple.id));
    }, 1000);
  };

  return (
    <div className="flex flex-col items-center justify-center h-[calc(100vh-140px)] space-y-12">
      <div className="text-center space-y-3">
         <h2 className="text-4xl font-serif font-bold text-[#1F1F1F]">电子木鱼</h2>
         <p className="text-stone-500 font-serif">轻触积累赛博功德，平复内心焦躁。</p>
      </div>

      <div className="relative">
          <motion.button
            whileTap={{ scale: 0.95 }}
            onClick={handleClick}
            className="w-64 h-64 rounded-full bg-gradient-to-br from-[#2c2c2c] to-[#000] border-8 border-stone-200 shadow-xl relative overflow-hidden group outline-none ring-1 ring-stone-300"
          >
             {/* Center Icon */}
             <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                 <svg viewBox="0 0 24 24" fill="currentColor" className="w-32 h-32 text-[#B8860B] opacity-80 group-hover:opacity-100 transition-opacity drop-shadow-lg">
                    <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 18c-4.41 0-8-3.59-8-8s3.59-8 8-8 8 3.59 8 8-3.59 8-8 8zm-5-9h10v2H7z"/>
                 </svg>
             </div>

             {/* Ripples */}
             {ripples.map(r => (
                 <motion.span
                    key={r.id}
                    initial={{ scale: 0, opacity: 0.5 }}
                    animate={{ scale: 4, opacity: 0 }}
                    transition={{ duration: 0.8 }}
                    style={{ left: r.x, top: r.y }}
                    className="absolute w-10 h-10 bg-[#fff] rounded-full pointer-events-none transform -translate-x-1/2 -translate-y-1/2 mix-blend-overlay"
                 />
             ))}
          </motion.button>

          {/* Floating Merits */}
          <div className="absolute -top-16 left-1/2 transform -translate-x-1/2 h-16 w-full flex justify-center pointer-events-none">
             {ripples.map(r => (
                 <motion.div
                    key={'text-' + r.id}
