import React, { useState, useEffect, useRef } from 'react';
import { sendMessageToOracle } from '../services/geminiService';
import { ChatMessage } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { PaperAirplaneIcon, SparklesIcon } from '@heroicons/react/24/solid';

const MotionDiv = motion.div as any;

const OracleChat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
        role: 'model',
        text: '求道者，幸会。您的命理档案已展开。今日有何困惑，不妨与天机阁一叙？',
        timestamp: Date.now()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendMessageToOracle(userMsg.text);
      const aiMsg: ChatMessage = {
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, {
          role: 'model',
          text: "天机混沌，连接中断。（网络错误）",
          timestamp: Date.now()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-120px)] glass-panel rounded-2xl overflow-hidden border border-stone-200 shadow-sm">
      {/* Chat Header */}
      <div className="p-4 border-b border-stone-200 bg-white/50 flex items-center justify-between backdrop-blur-md">
         <div className="flex items-center gap-3">
            <div className="w-2 h-2 rounded-full bg-[#8B0000] animate-pulse"></div>
            <h3 className="font-serif font-bold text-stone-800 text-lg">天机阁</h3>
         </div>
         <span className="text-xs text-stone-400 font-mono tracking-wider">GEMINI-2.5 // 档案已连接</span>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-8 bg-[#FDFDFB]">
        <AnimatePresence initial={false}>
            {messages.map((msg, idx) => (
            <MotionDiv 
                key={idx} 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
                <div 
                    className={`max-w-[85%] lg:max-w-[70%] p-5 rounded-2xl shadow-sm relative ${
                        msg.role === 'user' 
                        ? 'bg-[#1F1F1F] text-white rounded-br-none' 
                        : 'bg-white border border-stone-100 text-stone-700 rounded-bl-none'
                    }`}
                >
                    <div className="prose prose-sm max-w-none leading-relaxed whitespace-pre-wrap font-serif">
                        {msg.text.split('\n').map((line, i) => (
                            <p key={i} className={`mb-2 last:mb-0 ${msg.role === 'user' ? 'text-gray-200' : 'text-stone-700'}`}>{line}</p>
                        ))}
                    </div>
                    <div className={`mt-2 text-[10px] text-right uppercase tracking-widest opacity-60 ${msg.role === 'user' ? 'text-stone-400' : 'text-stone-400'}`}>
                        {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                    </div>
                </div>
            </MotionDiv>
            ))}
        </AnimatePresence>

        {isLoading && (
            <MotionDiv initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex justify-start">
                 <div className="bg-white border border-stone-100 p-4 rounded-2xl rounded-bl-none flex items-center gap-2 shadow-sm">
                    <SparklesIcon className="w-4 h-4 text-[#B8860B] animate-spin" />
                    <span className="text-xs text-stone-500 font-serif">正在推演天机...</span>
                 </div>
            </MotionDiv>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-stone-200">
        <div className="relative">
            <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                placeholder="在此输入您的困惑..."
                className="w-full bg-stone-50 text-stone-800 rounded-xl pl-4 pr-12 py-4 border border-stone-200 focus:border-[#B8860B] focus:ring-1 focus:ring-[#B8860B] focus:bg-white outline-none resize-none h-14 min-h-[56px] transition-all placeholder:text-stone-400"
                disabled={isLoading}
            />
            <button 
                onClick={handleSend}
                disabled={isLoading || !input.trim()}
                className="absolute right-2 top-2 bottom-2 aspect-square flex items-center justify-center bg-[#1F1F1F] hover:bg-[#333] text-[#B8860B] rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed shadow-md"
            >
                <PaperAirplaneIcon className="w-5 h-5 -ml-0.5" />
            </button>
        </div>
        <p className="text-[10px] text-stone-400 text-center mt-2 font-serif">
             AI亦有定数偏差，重要决策请从心。
        </p>
      </div>
    </div>
  );
};

export default OracleChat;

