    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Handle Initial Prompt (Deep link from Dashboard)
  useEffect(() => {
    if (initialPrompt && !hasProcessedPrompt.current && !isLoading) {
      hasProcessedPrompt.current = true;
      triggerMessage(initialPrompt);
      if (onPromptConsumed) {
        onPromptConsumed();
      }
    }
  }, [initialPrompt]);

  const triggerMessage = async (text: string) => {
    const userMsg: ChatMessage = {
        role: 'user',
        text: text,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, userMsg]);
      setIsLoading(true);

      try {
        const responseText = await sendMessageToOracle(userMsg.text);
