         <span className="text-xs text-stone-400 font-mono tracking-wider">GEMINI-2.5 // 档案已连接</span>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-8 bg-[#FDFDFB]">
        <AnimatePresence initial={false}>
            {messages.map((msg, idx) => (
            <MotionDiv 
                key={idx} 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
                <div 
                    className={`max-w-[85%] lg:max-w-[70%] p-5 rounded-2xl shadow-sm relative ${
                        msg.role === 'user' 
                        ? 'bg-[#1F1F1F] text-white rounded-br-none' 
                        : 'bg-white border border-stone-100 text-stone-700 rounded-bl-none'
                    }`}
                >
                    <div className="prose prose-sm max-w-none leading-relaxed whitespace-pre-wrap font-serif">
                        {msg.text.split('\n').map((line, i) => (
                            <p key={i} className={`mb-2 last:mb-0 ${msg.role === 'user' ? 'text-gray-200' : 'text-stone-700'}`}>{line}</p>
                        ))}
                    </div>
                    <div className={`mt-2 text-[10px] text-right uppercase tracking-widest opacity-60 ${msg.role === 'user' ? 'text-stone-400' : 'text-stone-400'}`}>
                        {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                    </div>
                </div>
            </MotionDiv>
            ))}
        </AnimatePresence>

        {isLoading && (
            <MotionDiv initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex justify-start">
