import React, { useState, useEffect, useRef } from 'react';
import { sendMessageToOracle } from '../services/geminiService';
import { ChatMessage, UserProfile } from '../types';
import { MOCK_PROFILES, USER_STATS } from '../services/mockDataService';
import { motion, AnimatePresence } from 'framer-motion';
import { PaperAirplaneIcon, SparklesIcon, UserCircleIcon, ArrowsRightLeftIcon } from '@heroicons/react/24/solid';

const MotionDiv = motion.div as any;
const MotionButton = motion.button as any;

interface OracleChatProps {
  initialPrompt?: string | null;
  onPromptConsumed?: () => void;
}

const OracleChat: React.FC<OracleChatProps> = ({ initialPrompt, onPromptConsumed }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
        role: 'model',
        text: '求道者，幸会。您的命理档案已展开。今日有何困惑，不妨与天机阁一叙？',
        timestamp: Date.now()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeProfile, setActiveProfile] = useState<UserProfile>(MOCK_PROFILES[0]);
  const [showProfileSwitcher, setShowProfileSwitcher] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const hasProcessedPrompt = useRef(false);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Handle Initial Prompt (Deep link from Dashboard)
  useEffect(() => {
    if (initialPrompt && !hasProcessedPrompt.current && !isLoading) {
      hasProcessedPrompt.current = true;
      triggerMessage(initialPrompt);
      if (onPromptConsumed) {
        onPromptConsumed();
      }
    }
  }, [initialPrompt]);

  const triggerMessage = async (text: string) => {
    const userMsg: ChatMessage = {
        role: 'user',
        text: text,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, userMsg]);
      setIsLoading(true);

      try {
        // Prepend context about WHO is being asked about
        const contextAwarePrompt = `[当前咨询对象：${activeProfile.name}, 关系：${activeProfile.relation}, 八字：${activeProfile.bazi || '未知'}] ${userMsg.text}`;

        const responseText = await sendMessageToOracle(contextAwarePrompt);
        const aiMsg: ChatMessage = {
          role: 'model',
          text: responseText,
          timestamp: Date.now()
        };
        setMessages(prev => [...prev, aiMsg]);
      } catch (error) {
        console.error(error);
        setMessages(prev => [...prev, {
            role: 'model',
            text: "天机混沌，连接中断。（网络错误）",
            timestamp: Date.now()
        }]);
      } finally {
        setIsLoading(false);
      }
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const textToSend = input;
    setInput(''); // Clear input early
    await triggerMessage(textToSend);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-120px)] relative">

      {/* 1. TOP STATS BAR */}
      <div className="bg-white/80 backdrop-blur-sm border-b border-stone-200 p-3 flex justify-between items-center text-[10px] text-stone-500 font-serif mb-2 rounded-xl shadow-sm">
         <div className="flex gap-4">
             <div>
                 <span className="block font-bold text-[#B8860B] text-base">{USER_STATS.consultations}</span>
                 <span>咨询次数</span>
             </div>
             <div>
                 <span className="block font-bold text-stone-800 text-base">{USER_STATS.daysActive}</span>
                 <span>陪伴天数</span>
             </div>
             <div>
                 <span className="block font-bold text-stone-800 text-base">{USER_STATS.memoriesArchived}</span>
                 <span>档案存储</span>
             </div>
         </div>
         <div className="text-right opacity-60">
             持续沟通<br/>修正运势
         </div>
      </div>

      {/* 2. CHAT CONTAINER */}
      <div className="flex-1 glass-panel rounded-2xl overflow-hidden border border-stone-200 shadow-sm flex flex-col relative">
        {/* Chat Header */}
        <div className="p-4 border-b border-stone-200 bg-white/50 flex items-center justify-between backdrop-blur-md">
            <div className="flex items-center gap-3">
                <div className="w-2 h-2 rounded-full bg-[#8B0000] animate-pulse"></div>
                <div>
                    <h3 className="font-serif font-bold text-stone-800 text-lg">天机阁</h3>
                    <p className="text-[10px] text-stone-400">正在为 <span className="text-[#8B0000] font-bold">{activeProfile.name}</span> 推演</p>
                </div>
            </div>
        </div>

        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto p-6 space-y-8 bg-[#FDFDFB]">
            <AnimatePresence initial={false}>
                {messages.map((msg, idx) => (
                <MotionDiv 
                    key={idx} 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                    <div 
                        className={`max-w-[85%] lg:max-w-[70%] p-5 rounded-2xl shadow-sm relative ${
                            msg.role === 'user' 
                            ? 'bg-[#1F1F1F] text-white rounded-br-none' 
                            : 'bg-white border border-stone-100 text-stone-700 rounded-bl-none'
                        }`}
                    >
                        <div className="prose prose-sm max-w-none leading-relaxed whitespace-pre-wrap font-serif">
                            {msg.text.split('\n').map((line, i) => (
                                <p key={i} className={`mb-2 last:mb-0 ${msg.role === 'user' ? 'text-gray-200' : 'text-stone-700'}`}>{line}</p>
                            ))}
                        </div>
                    </div>
                </MotionDiv>
                ))}
            </AnimatePresence>

            {isLoading && (
                <MotionDiv initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex justify-start">
                    <div className="bg-white border border-stone-100 p-4 rounded-2xl rounded-bl-none flex items-center gap-2 shadow-sm">
                        <SparklesIcon className="w-4 h-4 text-[#B8860B] animate-spin" />
                        <span className="text-xs text-stone-500 font-serif">正在推演天机...</span>
                    </div>
                </MotionDiv>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-white border-t border-stone-200">
            <div className="relative">
                <textarea
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={handleKeyPress}
                    placeholder={`关于${activeProfile.name}的困惑...`}
                    className="w-full bg-stone-50 text-stone-800 rounded-xl pl-4 pr-12 py-4 border border-stone-200 focus:border-[#B8860B] focus:ring-1 focus:ring-[#B8860B] focus:bg-white outline-none resize-none h-14 min-h-[56px] transition-all placeholder:text-stone-400"
                    disabled={isLoading}
                />
                <button 
                    onClick={handleSend}
                    disabled={isLoading || !input.trim()}
                    className="absolute right-2 top-2 bottom-2 aspect-square flex items-center justify-center bg-[#1F1F1F] hover:bg-[#333] text-[#B8860B] rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed shadow-md"
                >
                    <PaperAirplaneIcon className="w-5 h-5 -ml-0.5" />
                </button>
            </div>
        </div>
      </div>

      {/* 3. PROFILE SWITCHER FAB */}
      <div className="absolute bottom-24 right-4 z-20">
         <AnimatePresence>
            {showProfileSwitcher && (
                <MotionDiv 
                    initial={{ opacity: 0, scale: 0.9, y: 10 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.9, y: 10 }}
                    className="absolute bottom-14 right-0 bg-white border border-stone-200 rounded-xl shadow-xl w-48 overflow-hidden mb-2"
                >
                    <div className="p-2 bg-stone-50 border-b border-stone-100 text-xs font-bold text-stone-500 uppercase tracking-wider">切换咨询对象</div>
                    <div className="max-h-60 overflow-y-auto p-1">
                        {MOCK_PROFILES.map(p => (
                            <button
                                key={p.id}
                                onClick={() => { setActiveProfile(p); setShowProfileSwitcher(false); }}
                                className={`w-full text-left px-3 py-2 rounded-lg text-sm font-serif flex items-center gap-2 hover:bg-stone-50 transition-colors ${activeProfile.id === p.id ? 'bg-[#F7F7F5] text-[#8B0000]' : 'text-stone-700'}`}
                            >
                                <span className="w-2 h-2 rounded-full" style={{background: p.avatarColor}}></span>
                                {p.name}
                            </button>
                        ))}
                    </div>
                </MotionDiv>
            )}
         </AnimatePresence>

         <MotionButton 
            onClick={() => setShowProfileSwitcher(!showProfileSwitcher)}
            whileTap={{ scale: 0.9 }}
            className="w-12 h-12 bg-[#B8860B] text-white rounded-full shadow-lg flex items-center justify-center hover:bg-[#9A7009] transition-colors ring-4 ring-white"
            title="更换八字"
         >
             <ArrowsRightLeftIcon className="w-6 h-6" />
         </MotionButton>
      </div>
    </div>
  );
};

export default OracleChat;

import React, { useState, useEffect } from 'react';
import { getMemories, deleteMemory } from '../services/memoryService';
import { MOCK_REPORTS } from '../services/mockDataService';
