import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import OracleChat from './components/OracleChat';
import LifeDatabase from './components/LifeDatabase';
import { AppRoute } from './types';

function App() {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [initialChatPrompt, setInitialChatPrompt] = useState<string | null>(null);

  const handleNavigateToOracle = (prompt: string) => {
    setInitialChatPrompt(prompt);
    setRoute(AppRoute.ORACLE);
  };

  const renderContent = () => {
    switch (route) {
      case AppRoute.DASHBOARD:
        return <Dashboard onNavigateToChat={handleNavigateToOracle} />;
      case AppRoute.ORACLE:
        // Pass the prompt and a callback to clear it after consumption
        return (
          <OracleChat 
            initialPrompt={initialChatPrompt} 
            onPromptConsumed={() => setInitialChatPrompt(null)} 
          />
        );
      case AppRoute.DATABASE:
        return <LifeDatabase />;
      default:
        return <Dashboard onNavigateToChat={handleNavigateToOracle} />;
    }
  };

  return (
    <Layout currentRoute={route} setRoute={setRoute}>
      {renderContent()}
    </Layout>
  );
}

export default App;

import { DestinyReport } from '../types';
import { v4 as uuidv4 } from 'uuid';
import { MOCK_REPORTS } from './mockDataService';

const STORAGE_KEY = 'destiny_os_reports';

export const getReports = (): DestinyReport[] => {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (!stored) {
    // Initialize with mock data if empty
    localStorage.setItem(STORAGE_KEY, JSON.stringify(MOCK_REPORTS));
    return MOCK_REPORTS;
  }
  return JSON.parse(stored);
};

export const addReport = (
    title: string, 
    type: DestinyReport['type'], 
    summary: string, 
    tags: string[]
): DestinyReport => {
  const reports = getReports();
  const newReport: DestinyReport = {
    id: uuidv4(),
    title,
    type,
    summary,
    date: new Date().toISOString().split('T')[0],
    tags
  };

  // Add to beginning of list
  const updated = [newReport, ...reports];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  return newReport;
};

export const deleteReport = (id: string): void => {
  const reports = getReports();
  const updated = reports.filter(r => r.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
};

