import { GoogleGenAI, ChatSession, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from '../constants';
import { getContextString, addMemory } from './memoryService';

// Initialize Gemini Client
// In a real app, we would manage the instance lifecycle better, but this is fine for the demo.
let chatSession: ChatSession | null = null;
let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    if (!process.env.API_KEY) {
      console.error("API_KEY is missing from environment variables.");
      throw new Error("API Key missing");
    }
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

export const initializeChat = async () => {
  const client = getClient();
  const context = getContextString();

  const fullSystemInstruction = `${SYSTEM_INSTRUCTION}\n\nCURRENT USER CONTEXT (LIFE DATABASE):\n${context}`;

  chatSession = client.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: fullSystemInstruction,
      temperature: 0.7,
    },
  });
};

export const sendMessageToOracle = async (message: string): Promise<string> => {
  if (!chatSession) {
    await initializeChat();
  }

  if (!chatSession) {
    throw new Error("Failed to initialize chat session");
  }

  try {
    const response = await chatSession.sendMessage({ message });

    // Simulate "Memory Extraction" (Post-processing)
    // In a real app, we might run a second lightweight LLM call to extract facts.
    // Here, we'll just heuristically save the interaction if it's long enough as an "event".
    if (message.length > 20 && Math.random() > 0.7) {
        addMemory(`User asked about: "${message.substring(0, 50)}..."`, 'EVENT');
    }

    return response.text || "The Oracle is silent (No response text).";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "The cosmic connection is disrupted. Please check your API key or network.";
  }
};

/**
 * Generates a structured report based on a topic.
 * Returns a JSON object with title, summary, and content.
 */
export const generateReportContent = async (topic: string, profileInfo: string): Promise<{title: string, summary: string}> => {
    const client = getClient();

    const prompt = `
    TASK: Generate a professional Metaphysics Destiny Report.
    TOPIC: ${topic}
    PROFILE: ${profileInfo}

    REQUIREMENTS:
    1. Create a mystical yet professional title (4-10 words).
    2. Write a concise summary (1-2 sentences) of the fortune prediction.
    3. Return ONLY a JSON object.

    JSON Schema:
    {
        "title": "string",
        "summary": "string"
    }
    `;

    try {
        const response = await client.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        summary: { type: Type.STRING }
                    }
                }
            }
        });

        const text = response.text;
        if (!text) throw new Error("Empty response");
        return JSON.parse(text);

    } catch (e) {
        console.error("Report Generation Failed", e);
        return {
            title: `${topic} - 命理详批`,
            summary: "天机晦涩，无法生成详细摘要，但您可以查看对话记录。"
        };
    }
}

