  }, [initialPrompt]);

  const handleSendMessage = async (text: string) => {
    const userMsg: ChatMessage = {
        role: 'user',
        text: text,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, userMsg]);
      setIsLoading(true);

      try {
        // Prepend context about WHO is being asked about
        const contextAwarePrompt = `[当前咨询对象：${activeProfile.name}, 关系：${activeProfile.relation}, 八字：${activeProfile.bazi || '未知'}] ${userMsg.text}`;

        const responseText = await sendMessageToOracle(contextAwarePrompt);
        const aiMsg: ChatMessage = {
          role: 'model',
          text: responseText,
          timestamp: Date.now()
        };
        setMessages(prev => [...prev, aiMsg]);
      } catch (error) {
        console.error(error);
        setMessages(prev => [...prev, {
            role: 'model',
            text: "天机混沌，连接中断。（网络错误）",
            timestamp: Date.now()
        }]);
      } finally {
        setIsLoading(false);
      }
  };

  const handleSendClick = async () => {
    if (!input.trim() || isLoading) return;
    const textToSend = input;
    setInput(''); // Clear input early
    await handleSendMessage(textToSend);
  };

