          console.error(e);
          setMessages(prev => [...prev, { role: 'model', text: "报告生成失败，请稍后重试。", timestamp: Date.now() }]);
      } finally {
          setIsLoading(false);
          setIsGeneratingReport(false);
      }
  };

  const handleCustomReportPay = async () => {
      if (!customReportTopic.trim()) return;
      setPaymentProcessing(true);

