         <div className="flex gap-4">
             <div>
                 <span className="block font-bold text-[#B8860B] text-base">{USER_STATS.consultations}</span>
                 <span>咨询次数</span>
             </div>
             <div>
                 <span className="block font-bold text-stone-800 text-base">{USER_STATS.daysActive}</span>
                 <span>陪伴天数</span>
             </div>
         </div>
         <div className="text-right opacity-60">
             持续沟通<br/>修正运势
         </div>
      </div>

      {/* 2. CHAT CONTAINER */}
      <div className="flex-1 glass-panel rounded-2xl overflow-hidden border border-stone-200 shadow-sm flex flex-col relative">
        {/* Chat Header */}
        <div className="p-4 border-b border-stone-200 bg-white/50 flex items-center justify-between backdrop-blur-md">
            <div className="flex items-center gap-3">
                <div className="w-2 h-2 rounded-full bg-[#8B0000] animate-pulse"></div>
                <div>
                    <h3 className="font-serif font-bold text-stone-800 text-lg">天机阁</h3>
                    <p className="text-[10px] text-stone-400">正在为 <span className="text-[#8B0000] font-bold">{activeProfile.name}</span> 推演</p>
                </div>
            </div>
        </div>

        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto p-6 space-y-8 bg-[#FDFDFB]">
            <AnimatePresence initial={false}>
                {messages.map((msg, idx) => (
                <MotionDiv 
                    key={idx} 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
