      <AnimatePresence mode="wait">
        {activeTab === 'MEMORIES' ? (
            <MotionDiv
                key={`memories-container-${selectedProfileId}`}
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: 10 }}
                transition={{ duration: 0.2 }}
                className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4"
            >
                {filteredMemories.length > 0 ? (
                    filteredMemories.map((memory) => (
                        <div
                            key={memory.id}
                            className="bg-white p-6 rounded-xl border border-stone-200 shadow-sm hover:shadow-md hover:border-[#B8860B]/30 transition-all group relative flex flex-col"
                        >
                            <div className="flex justify-between items-start mb-4">
                                <span className={`text-[10px] px-2 py-1 rounded font-bold tracking-wider border ${getCategoryColor(memory.category)}`}>
                                    {getCategoryLabel(memory.category)}
                                </span>
                                <button 
                                    onClick={() => handleDeleteMemory(memory.id)}
                                    className="text-stone-300 hover:text-[#8B0000] transition-colors p-1"
                                    title="删除此条记忆"
                                >
                                    <TrashIcon className="w-4 h-4" />
                                </button>
                            </div>
                            <p className="text-stone-700 text-sm leading-relaxed font-serif flex-1">
                                {memory.content}
                            </p>
                            <div className="mt-5 pt-4 border-t border-stone-100 flex items-center justify-between text-[10px] text-stone-400 font-mono">
                                <span className="flex items-center gap-1" title="AI置信度">
                                    <TagIcon className="w-3 h-3" />
                                    {Math.round(memory.confidence * 100)}%
                                </span>
                                <span>
                                    {new Date(memory.timestamp).toLocaleDateString('zh-CN')}
                                </span>
                            </div>
                        </div>
                    ))
                ) : (
                    <div className="col-span-full py-12 flex flex-col items-center justify-center text-stone-400">
                        <DocumentTextIcon className="w-12 h-12 mb-2 opacity-20" />
                        <p className="font-serif text-sm">此档案暂无记忆碎片</p>
                    </div>
                )}

                {/* Add Memory Placeholder */}
                <div className="border-2 border-dashed border-stone-200 rounded-xl p-5 flex flex-col items-center justify-center text-stone-400 cursor-not-allowed bg-stone-50/50 hover:bg-stone-100 transition-colors min-h-[150px] group">
                    <div className="w-10 h-10 rounded-full bg-stone-100 flex items-center justify-center mb-2 group-hover:scale-110 transition-transform">
                        <span className="text-xl font-light text-stone-400">+</span>
                    </div>
                    <span className="text-sm font-serif font-bold text-stone-500">手动录入记忆</span>
                    <span className="text-xs mt-1 text-stone-400">(即将开放)</span>
                </div>
            </MotionDiv>
        ) : (
            <MotionDiv
                key={`reports-container-${selectedProfileId}`}
                initial={{ opacity: 0, x: 10 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -10 }}
                transition={{ duration: 0.2 }}
                className="grid grid-cols-1 gap-6"
            >
                {filteredReports.length > 0 ? (
                    filteredReports.map((report) => (
                        <div
                            key={report.id}
                            className={`relative overflow-hidden rounded-2xl border transition-all cursor-pointer group ${
                                report.type === 'K_LINE' 
                                ? 'bg-[#1F1F1F] text-[#F7F7F5] border-[#333] shadow-lg' 
                                : 'bg-white text-stone-800 border-stone-200 shadow-sm hover:border-[#B8860B]/30'
                            }`}
                        >
                            {/* Visual Background for K-Line reports */}
                            {report.type === 'K_LINE' && (
                                <div className="absolute inset-0 opacity-20 pointer-events-none">
                                    <svg width="100%" height="100%" preserveAspectRatio="none">
                                        <path d="M0,100 C150,50 250,120 400,60 L400,200 L0,200 Z" fill="url(#grad1)" />
                                        <defs>
                                            <linearGradient id="grad1" x1="0%" y1="0%" x2="0%" y2="100%">
                                                <stop offset="0%" style={{stopColor:'#B8860B', stopOpacity:1}} />
                                                <stop offset="100%" style={{stopColor:'#1F1F1F', stopOpacity:1}} />
                                            </linearGradient>
                                        </defs>
                                    </svg>
                                </div>
                            )}

                            <div className="flex flex-col md:flex-row h-full relative z-10">
                                {/* Left Indicator */}
                                <div className={`w-full md:w-2 ${report.type === 'K_LINE' ? 'bg-[#B8860B]' : 'bg-stone-200 group-hover:bg-[#B8860B] transition-colors'}`}></div>

                                <div className="p-6 flex-1 flex flex-col justify-center">
                                    <div className="flex justify-between items-start mb-3">
                                        <div className="flex items-center gap-2">
                                            {report.type === 'K_LINE' ? (
                                                <ChartBarIcon className="w-5 h-5 text-[#B8860B]" />
                                            ) : (
                                                <DocumentTextIcon className="w-5 h-5 text-[#B8860B]" />
                                            )}
                                            <span className={`text-xs font-bold tracking-[0.2em] uppercase ${report.type === 'K_LINE' ? 'text-stone-400' : 'text-[#8B0000]'}`}>
                                                {report.type === 'K_LINE' ? '全息图表' : '深度命书'}
                                            </span>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <span className={`text-xs font-mono ${report.type === 'K_LINE' ? 'text-stone-500' : 'text-stone-400'}`}>
                                                {report.date}
                                            </span>
                                            <button 
                                                onClick={(e) => handleDeleteReport(e, report.id)}
                                                className="text-stone-300 hover:text-red-500 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                                                title="销毁报告"
                                            >
                                                <TrashIcon className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </div>

                                    <h3 className={`text-2xl font-serif font-bold mb-2 ${report.type === 'K_LINE' ? 'text-[#F7F7F5]' : 'text-[#1F1F1F]'}`}>
                                        {report.title}
                                    </h3>

                                    <p className={`text-sm leading-relaxed mb-4 line-clamp-2 ${report.type === 'K_LINE' ? 'text-stone-400' : 'text-stone-600'}`}>
                                        {report.summary}
                                    </p>

                                    <div className="flex items-center justify-between mt-auto">
                                        <div className="flex gap-2">
                                            {report.tags.map(tag => (
                                                <span key={tag} className={`text-[10px] px-2 py-1 rounded-md border ${
                                                    report.type === 'K_LINE' 
                                                    ? 'border-stone-700 bg-stone-800 text-stone-300' 
                                                    : 'border-stone-100 bg-stone-50 text-stone-500'
                                                }`}>
                                                    #{tag}
                                                </span>
                                            ))}
                                        </div>
                                        <div className={`flex items-center gap-1 text-xs font-medium opacity-0 group-hover:opacity-100 transition-opacity ${report.type === 'K_LINE' ? 'text-[#B8860B]' : 'text-[#8B0000]'}`}>
                                            <span>查看详情</span>
                                            <ArrowTopRightOnSquareIcon className="w-3 h-3" />
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))
                ) : (
                    <div className="py-12 flex flex-col items-center justify-center text-stone-400">
                        <UserIcon className="w-12 h-12 mb-2 opacity-20" />
                        <p className="font-serif text-sm">此档案暂无深度报告</p>
                    </div>
                )}
            </MotionDiv>
        )}
      </AnimatePresence>
    </div>
  );
};

export default LifeDatabase;

export interface Memory {
  id: string;
  profileId?: string; // Linked to UserProfile.id
  content: string;
  category: 'FACT' | 'EMOTION' | 'EVENT' | 'PREDICTION';
  timestamp: number;
  confidence: number; // 0-1
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
  relatedMemories?: string[]; // IDs of memories used for this answer
}

export interface FiveElementsData {
  subject: string;
  A: number; // User Value
  fullMark: number;
}

export interface EnergyPoint {
  time: string;
  energy: number;
}

export interface UserProfile {
  id: string;
  name: string;
  gender: 'MALE' | 'FEMALE'; // New Field
  phone?: string; // New Field
  email?: string; // New Field
  relation: 'SELF' | 'FAMILY' | 'CLIENT' | 'FRIEND';
  birthDate: string; // YYYY-MM-DD
  birthTime: string; // HH:mm
  bazi?: string; // e.g. "乙亥 丙子..."
  avatarColor: string;
}

export interface DestinyReport {
  id: string;
  profileId?: string; // Linked to UserProfile.id
  title: string;
  type: 'YEARLY' | 'CAREER' | 'WEALTH' | 'RELATIONSHIP' | 'K_LINE';
  summary: string;
  date: string;
  tags: string[];
}

export enum AppRoute {
  DASHBOARD = 'dashboard',
  ORACLE = 'oracle',
  DATABASE = 'database'
}

import React, { useState, useEffect } from 'react';
import { getMemories, deleteMemory } from '../services/memoryService';
import { getReports, deleteReport } from '../services/reportService';
import { MOCK_PROFILES } from '../services/mockDataService';
import { Memory, DestinyReport, UserProfile } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { 
    TrashIcon, TagIcon, DocumentTextIcon, ChartBarIcon, 
    ArrowTopRightOnSquareIcon, ChevronDownIcon, ChevronUpIcon, 
    PlusIcon, UserIcon, PhoneIcon, EnvelopeIcon, 
    PowerIcon, CloudArrowUpIcon, FingerPrintIcon
