const MotionDiv = motion.div as any;

const LifeDatabase: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'MEMORIES' | 'REPORTS'>('MEMORIES');
  const [memories, setMemories] = useState<Memory[]>([]);
  const [reports, setReports] = useState<DestinyReport[]>([]);

  // Profile State
  const [selectedProfileId, setSelectedProfileId] = useState<string>('self');
  const [isOthersExpanded, setIsOthersExpanded] = useState(false);

  // Auth State (Mock)
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);

  // Derived Data
  const displayProfile = MOCK_PROFILES.find(p => p.id === selectedProfileId) || MOCK_PROFILES[0];
  const listProfiles = MOCK_PROFILES.filter(p => p.id !== selectedProfileId);

  // Filter Data for Display
  const filteredMemories = memories.filter(m => (m.profileId || 'self') === selectedProfileId);
  const filteredReports = reports.filter(r => (r.profileId || 'self') === selectedProfileId);

  useEffect(() => {
    setMemories(getMemories());
    setReports(getReports());
