  const getCategoryLabel = (cat: string) => {
      switch (cat) {
          case 'FACT': return '事实';
          case 'EMOTION': return '情绪';
          case 'EVENT': return '事件';
          case 'PREDICTION': return '预言';
          default: return '其他';
