                </p>
            </div>
            {/* TAB SWITCHER */}
            <div className="flex bg-stone-200/50 p-1.5 rounded-xl shrink-0 self-start md:self-end">
                <button 
                    onClick={() => setActiveTab('MEMORIES')}
