                      </button>

                      {isLoggedIn && (
                          <button className="flex-1 flex items-center justify-center gap-1 py-1.5 rounded-lg text-xs font-bold bg-[#F7F7F5] border border-stone-200 text-stone-500 hover:text-[#B8860B] transition-colors">
                              <CloudArrowUpIcon className="w-3 h-3" />
