                  >
                      <h3 className="text-xl font-bold mb-4 font-serif text-[#B8860B]">
                          {activeModal === 'USER_AGREEMENT' && '用户协议'}
                          {activeModal === 'PRIVACY' && '隐私政策'}
                          {activeModal === 'FEEDBACK' && '投诉与建议'}
                      </h3>

                      <div className="text-sm text-stone-600 leading-relaxed space-y-2 mb-6">
                          {activeModal === 'USER_AGREEMENT' && (
                              <p>欢迎使用天命系统。本服务基于人工智能技术，提供的命理分析仅供娱乐和参考，不构成任何专业建议...</p>
                          )}
                          {activeModal === 'PRIVACY' && (
                              <p>我们非常重视您的隐私。您的八字信息和对话记录仅用于生成运势报告，且仅存储于本地（除非您开启云同步）...</p>
                          )}
                          {activeModal === 'FEEDBACK' && (
                              <textarea 
                                className="w-full h-32 p-3 bg-stone-50 border border-stone-200 rounded-xl focus:border-[#B8860B] outline-none resize-none"
                                placeholder="请输入您的宝贵建议..."
                              />
                          )}
                      </div>

                      <button 
                        onClick={() => {
                            if(activeModal === 'FEEDBACK') alert('感谢您的反馈！');
                            setActiveModal('NONE');
                        }}
                        className="w-full py-3 bg-[#1F1F1F] text-[#F7F7F5] rounded-xl font-bold hover:bg-[#333]"
                      >
                          {activeModal === 'FEEDBACK' ? '提交反馈' : '我已阅读'}
                      </button>
                  </MotionDiv>
              </div>
          )}
      </AnimatePresence>

    </div>
  );
};

