  const [activeTab, setActiveTab] = useState<'MEMORIES' | 'REPORTS'>('MEMORIES');
  const [memories, setMemories] = useState<Memory[]>([]);
  const [reports, setReports] = useState<DestinyReport[]>([]);
  const [profiles, setProfiles] = useState<UserProfile[]>([]);

  // Profile State
  const [selectedProfileId, setSelectedProfileId] = useState<string>('self');
  const [isOthersExpanded, setIsOthersExpanded] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  // Edit Form State
  const [editForm, setEditForm] = useState<Partial<UserProfile>>({});

  useEffect(() => {
    setMemories(getMemories());
    setReports(getReports());
    setProfiles(getProfiles());
  }, []); 

  // Derived Data
  const displayProfile = profiles.find(p => p.id === selectedProfileId) || profiles[0];
  const listProfiles = profiles.filter(p => p.id !== selectedProfileId);

  const filteredMemories = memories.filter(m => (m.profileId || 'self') === selectedProfileId);
  const filteredReports = reports.filter(r => (r.profileId || 'self') === selectedProfileId);

  const handleDeleteMemory = (id: string) => {
    deleteMemory(id);
    setMemories(getMemories());
  };

  const handleDeleteReport = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      if(confirm('确定要销毁这份珍贵的命理报告吗？')) {
          deleteReport(id);
          setReports(getReports());
      }
  }

  const openEditModal = () => {
      setEditForm({ ...displayProfile });
      setIsEditModalOpen(true);
  };

  const handleSaveProfile = () => {
      if (displayProfile && editForm) {
          const updatedProfiles = updateProfile(displayProfile.id, editForm);
          setProfiles(updatedProfiles);
          setIsEditModalOpen(false);
