                            onClick={handleSaveProfile}
                            className="flex-[2] py-3 bg-[#1F1F1F] text-[#F7F7F5] rounded-xl font-bold hover:bg-[#333] shadow-lg flex items-center justify-center gap-2"
                          >
                              <PencilSquareIcon className="w-4 h-4" />
                              重新排盘并保存
                          </button>
                      </div>
                  </MotionDiv>
              </div>
          )}
      </AnimatePresence>
    </div>
  );
};

export default LifeDatabase;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import OracleChat from './components/OracleChat';
import LifeDatabase from './components/LifeDatabase';
import Mine from './components/Mine';
import { AppRoute } from './types';

function App() {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [initialChatPrompt, setInitialChatPrompt] = useState<string | null>(null);

  const handleNavigateToOracle = (prompt: string) => {
    setInitialChatPrompt(prompt);
    setRoute(AppRoute.ORACLE);
  };

  const renderContent = () => {
    switch (route) {
      case AppRoute.DASHBOARD:
        return <Dashboard onNavigateToChat={handleNavigateToOracle} />;
      case AppRoute.ORACLE:
        // Pass the prompt and a callback to clear it after consumption
        return (
          <OracleChat 
            initialPrompt={initialChatPrompt} 
            onPromptConsumed={() => setInitialChatPrompt(null)} 
          />
        );
      case AppRoute.DATABASE:
        return <LifeDatabase />;
      case AppRoute.MINE:
        return <Mine />;
      default:
        return <Dashboard onNavigateToChat={handleNavigateToOracle} />;
    }
  };

  return (
    <Layout currentRoute={route} setRoute={setRoute}>
      {renderContent()}
    </Layout>
  );
}

export default App;

