                    className="bg-white w-full max-w-sm rounded-2xl p-0 relative z-10 shadow-2xl overflow-hidden"
                  >
                      {/* Decoration Header */}
                      <div className="h-24 bg-gradient-to-br from-[#1F1F1F] to-[#333] relative flex items-center justify-center">
